class Solution:
    def numTriplets(self, nums1, nums2):
        total = 0
        n1, n2 = len(nums1), len(nums2)
        for i in range(n1):
            sq = nums1[i] * nums1[i]
            for j in range(n2):
                for k in range(j + 1, n2):
                    if nums2[j] * nums2[k] == sq:
                        total += 1
        for i in range(n2):
            sq = nums2[i] * nums2[i]
            for j in range(n1):
                for k in range(j + 1, n1):
                    if nums1[j] * nums1[k] == sq:
                        total += 1
        return total

