class Solution:
    def numTriplets(self, nums1, nums2):
        from collections import Counter

        def countPairs(squares_source, pair_source):
            counter = Counter()
            n = len(pair_source)
            for j in range(n):
                for k in range(j + 1, n):
                    counter[pair_source[j] * pair_source[k]] += 1
            total = 0
            for x in squares_source:
                total += counter.get(x * x, 0)
            return total

        return countPairs(nums1, nums2) + countPairs(nums2, nums1)

