var numTriplets = function(nums1, nums2) {
    function countPairs(squaresSource, pairSource) {
        const counter = new Map();
        const n = pairSource.length;
        for (let j = 0; j < n; j++) {
            for (let k = j + 1; k < n; k++) {
                const p = pairSource[j] * pairSource[k];
                counter.set(p, (counter.get(p) || 0) + 1);
            }
        }
        let total = 0;
        for (const x of squaresSource) {
            const sq = x * x;
            total += counter.get(sq) || 0;
        }
        return total;
    }
    return countPairs(nums1, nums2) + countPairs(nums2, nums1);
};
